SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_lon_m_contract ON sc_lon_m_contract CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_contract() RETURNS trigger AS $BODY$
declare
    li_rc integer;
    ls_keep_intarr sc_kep_m_keeping_constant.int_arrear_status%type;
BEGIN
  BEGIN

  /* ---- ห้ามเปิดเพราะจะขึ้น Error Mutating
  if :new.loan_contract_no is null or :new.loan_contract_no =' ' then
    spa_dberrcol('sc_lon_m_contract','loan_contract_no',:new.loan_contract_no);
  else
    if :old.loan_contract_no is null or :old.loan_contract_no <> :new.loan_contract_no then
      if pka_com_valid.loan_contract_no(trim(:new.loan_contract_no)) = '1' then
        spa_dberrcol('sc_lon_m_contract','loan_contract_no',:new.loan_contract_no||',มีอยุ่แล้วในระบบ');
      end if;
    end if;
  end if; */
  --//-- Insert  
    if coalesce(OLD.loan_contract_no::text, '') = '' then
        if pka.auto_entry then

            if coalesce(NEW.appove_officer::text, '') = '' then NEW.appove_officer := current_setting('app.login_id', true);end if;
            if coalesce(NEW.branch_id::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;

        end if;
    end if;

    if coalesce(NEW.loan_objective_code::text, '') = '' or NEW.loan_objective_code = ' ' then
        NEW.loan_objective_code := '00';
    end if;

    if coalesce(NEW.loan_request_amount::text, '') = '' then
        NEW.loan_request_amount := 0;
    end if;

    if coalesce(NEW.loan_approve_amount::text, '') = '' then
        NEW.loan_approve_amount := 0;
    end if;

    if coalesce(NEW.real_recieve::text, '') = '' then
        NEW.real_recieve := 0;
    end if;

    if coalesce(NEW.loan_payment_type_code::text, '') = '' or NEW.loan_payment_type_code = ' ' then
        NEW.loan_payment_type_code := '01';
    else
        if coalesce(OLD.loan_payment_type_code::text, '') = '' or OLD.loan_payment_type_code <> NEW.loan_payment_type_code then
            if NEW.loan_payment_type_code not in (
                '01',
                '02',
                '03'
            ) then -- 01:คงต้น 02:คงยอด 03:อัตราก้าวหน้า
                CALL spa_dberrcol('sc_lon_m_contract', 'loan_payment_type_code', NEW.loan_payment_type_code);
            end if;

        end if;
    end if;

    if coalesce(NEW.loan_installment_amount::text, '') = '' then
        NEW.loan_installment_amount := 0;
    end if;

    if coalesce(NEW.period_payment_amount::text, '') = '' then
        NEW.period_payment_amount := 0;
    end if;

    if coalesce(NEW.last_payment_amount::text, '') = '' then
        NEW.last_payment_amount := 0;
    end if;

    if coalesce(NEW.start_keep_date::text, '') = '' then
        NEW.start_keep_date := NEW.BEGINing_of_contract;
    end if;

    if coalesce(NEW.rec_rep_status::text, '') = '' or NEW.rec_rep_status = ' ' then
        NEW.rec_rep_status := '2';
    end if;

    if OLD.rec_rep_status = '2' and NEW.rec_rep_status = '1' then
    -- จ่ายเงินกู้
        NEW.paid_loan_id := current_setting('app.login_id', true);
        NEW.paid_loan_br := current_setting('app.login_br', true);
        NEW.paid_loan_date := statement_timestamp();
    end if;

    if coalesce(NEW.create_loan_status::text, '') = '' or NEW.create_loan_status = ' ' then
        NEW.create_loan_status := '2';
    end if;

    if OLD.create_loan_status = '2' and NEW.create_loan_status = '1' then
    -- ตั้งหนี้เงินกู้
        NEW.create_entry_id := current_setting('app.login_id', true);
        NEW.create_branch_id := current_setting('app.login_br', true);
    end if;


    if coalesce(NEW.atm_status::text, '') = '' or NEW.atm_status != '1' then
        NEW.atm_status := '0';
    end if;

    if coalesce(NEW.group_pay::text, '') = '' then
        NEW.group_pay := 0;
    end if;

    if coalesce(NEW.trans_bank_status::text, '') = '' or NEW.trans_bank_status != '1' then
        NEW.trans_bank_status := '0';
    end if;

    if coalesce(NEW.paid_multi::text, '') = '' or NEW.paid_multi != '1' then
        NEW.paid_multi := '0';
    end if;

    if coalesce(NEW.con_contract_period::text, '') = '' then
        NEW.con_contract_period := 0;
    end if;

    if coalesce(NEW.paid_first_amount::text, '') = '' then
        NEW.paid_first_amount := 0;
    end if;

    if coalesce(NEW.fin_status::text, '') = '' or NEW.fin_status != '1' then
        NEW.fin_status := '0';
    end if;

    if (OLD.loan_type IS NOT NULL AND OLD.loan_type::text <> '') and OLD.loan_type != NEW.loan_type and (NEW.loan_type IS NOT NULL AND NEW.loan_type::text <> '') then
        select count(1) into STRICT li_rc 
        from sc_lon_m_loan_card
        where loan_contract_no = NEW.loan_contract_no;
        if li_rc > 0 then
            update sc_lon_m_loan_card
            set loan_type = NEW.loan_type
            where loan_contract_no = NEW.loan_contract_no;
        end if;
    end if;

    --Niorn 3/7/2019 เก็บงวดผ่อน ครั้งแรก
    if ( coalesce(NEW.first_install::text, '') = '' or NEW.first_install = 0 ) and NEW.loan_installment_amount > 0  then
        NEW.first_install := NEW.loan_installment_amount;
    end if;

    if ( coalesce(NEW.first_period::text, '') = '' or NEW.first_period = 0 ) and NEW.period_payment_amount > 0  then
        NEW.first_period := NEW.period_payment_amount;
    end if;

    --Niorn 2024-08-20 MWA
    if ( coalesce(NEW.first_paytype::text, '') = '' or NEW.first_paytype = '' ) then
        NEW.first_paytype := NEW.loan_payment_type_code;
    end if;

    --nkpt nonn nksw หักแบบคงยอด ให้เซท fixed_amount ไปเลย ไม่ให้เก็บเกิน
    --Niorn 2022-07-03 TGE ( บวกดอกเบี้ยค้างทีหลัง ) เบิ้ลต้น เก็บเกินงวดผ่อนได้
    --fixed_payment ไม่มีผลถ้า config sc_kep_m_keeping_constant.int_arrear_status = '1' ( บวกดอกเบี้ยค้างทีหลัง )
    --ถ้า config sc_kep_m_keeping_constant.int_arrear_status = '1' ( บวกดอกเบี้ยค้างทีหลัง ) ต้องไม่ ใช้ trigger ด้านล่าง
    if pka.isCoop('JAN') = '1' then
       --บวกดอกเบี้ยค้างก่อน แต่ให้ เก็บเกินงวดผ่อนได้
        null;
    else

        --Niorn 2024-04-01 AOT เพิ่ม exception 
        BEGIN
            select coalesce( int_arrear_status , '0' )
            into STRICT ls_keep_intarr
            from sc_kep_m_keeping_constant;
         EXCEPTION when others then   ls_keep_intarr := '0';
         end;

        if ls_keep_intarr = '1' then
           -- บวกดอกเบี้ยค้างทีหลัง  เบิ้ลต้น เก็บเกินงวดผ่อนได้
            null;
        else
            if OLD.loan_payment_type_code <> NEW.loan_payment_type_code
                or OLD.create_loan_status <> NEW.create_loan_status
                or OLD.period_payment_amount <> NEW.period_payment_amount then
                    if NEW.loan_payment_type_code  ='02' then
                        update sc_lon_m_loan_card
                        set   fixed_payment = NEW.period_payment_amount
                        where loan_contract_no = NEW.loan_contract_no
;
                    else
                        update sc_lon_m_loan_card
                        set   fixed_payment = 0
                        where loan_contract_no = NEW.loan_contract_no
;
                    end if;
            end if;
        end if;
    end if;

  --SKLA แก้ loan_type ให้ up ใน Card ด้วย
  if OLD.loan_type <> NEW.loan_type then
        update sc_lon_m_loan_card
        set   loan_type = NEW.loan_type
        where loan_contract_no = NEW.loan_contract_no;
  end if;


--ยกเลิกตั้งหนี้ fin status = '0'
if NEW.rec_rep_status = '2'  then

    update sc_fin_vourcher_head
    set cancel_status = '1'
    where vourcher_no = NEW.vourcher_no;

    NEW.fin_status :='0';
    NEW.vourcher_no := '';

end if;

--Niorn 2023-09-18 TGE
--Ending of contract = fp_RelativeMonth( begining_of_contract + 1 , loan_installment_amount )
--if :new.ending_of_contract is null then
--    :new.ending_of_contract := PKA_SRV_DATETIME.fp_RelativeMonth ( PKA_SRV_DATETIME.fp_LastDayOfMonth ( :new.begining_of_contract ) , :new.loan_installment_amount )  ;
--end if ;
    if coalesce(NEW.member_group_no::text, '') = '' then
        NEW.member_group_no := PKA_COM_FUNCTION.fp_get_member_group( NEW.membership_no );
    end if;

  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_lon_m_contract() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_lon_m_contract
	BEFORE INSERT OR UPDATE ON sc_lon_m_contract FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_lon_m_contract();

